268	std::string decide_human_actions() {
269	    std::string actions_str(M_humans_global, '.');
270	    std::vector<Point> tentative_walls_this_turn; 
271	    std::vector<Point> tentative_move_targets_this_turn(M_humans_global, INVALID_POINT); 
272	
273	    for (int i = 0; i < M_humans_global; ++i) {
274	        HumanInfo& human = humans_global_state[i];
275	
276	        int unbuilt_walls_count = 0;
277	        for (const auto& wall_cell : human.assigned_wall_cells) {
278	            if (is_valid_point(wall_cell) && !is_impassable_grid_static[wall_cell.r][wall_cell.c]) {
279	                unbuilt_walls_count++;
280	            }
281	        }
282	
283	        if (unbuilt_walls_count == 0) { 
284	             human.objective = (human.pos == human.final_stand_pos) ? 
285	                              HumanObjective::STAYING_IN_SAFE_SPOT : 
286	                              HumanObjective::GOING_TO_SAFE_SPOT;
287	        } else { 
288	            human.objective = HumanObjective::BUILDING_WALLS;
289	        }
290	        
291	        if(human.objective == HumanObjective::BUILDING_WALLS && human.turns_stuck_building >= MAX_STUCK_TURNS) {
292	            human.objective = HumanObjective::REPOSITIONING_STUCK; 
293	        }
294	
295	        char chosen_action_for_human_i = '.';
296	        if (human.objective == HumanObjective::STAYING_IN_SAFE_SPOT) {
297	            chosen_action_for_human_i = '.';
298	        } else if (human.objective == HumanObjective::GOING_TO_SAFE_SPOT || 
299	                   human.objective == HumanObjective::REPOSITIONING_STUCK) {
300	            if(human.objective == HumanObjective::REPOSITIONING_STUCK) human.turns_stuck_building = 0; 
301	
302	            chosen_action_for_human_i = get_bfs_move_char(human.pos, human.final_stand_pos, tentative_walls_this_turn);
303	        
304	        } else if (human.objective == HumanObjective::BUILDING_WALLS) {
305	            Point best_wall_target = INVALID_POINT;
306	            Point best_stand_point = INVALID_POINT;
307	            int min_eval_score = INF;
308	
309	            for (const auto& wall_coord : human.assigned_wall_cells) {
310	                if (!is_valid_point(wall_coord) || is_impassable_grid_static[wall_coord.r][wall_coord.c]) continue;
311	                if (!can_theoretically_build_at(wall_coord, human.id)) continue;
312	
313	                int adj_wall_bonus_val = count_adjacent_walls_or_boundaries(wall_coord) * ADJACENT_WALL_PRIORITY_BONUS;
314	                int current_near_pet_penalty = 0; // NEAR_PET_PENALTY_POINTS_PER_PET is 0
315	
316	                for (int k_dir_idx = 0; k_dir_idx < 4; ++k_dir_idx) { 
317	                    Point potential_stand_pos = {wall_coord.r + DIRS[k_dir_idx].r, 
318	                                                 wall_coord.c + DIRS[k_dir_idx].c};
319	                    
320	                    if (!is_valid_point(potential_stand_pos) || is_impassable_grid_static[potential_stand_pos.r][potential_stand_pos.c]) continue;
321	                    
322	                    bool conflict_with_tentative_wall_build_spot = false; 
323	                    for(const auto& tw : tentative_walls_this_turn) { if(potential_stand_pos == tw) { conflict_with_tentative_wall_build_spot = true; break; }}
324	                    if(conflict_with_tentative_wall_build_spot) continue;
325	                    
326	                    bool conflict_with_tentative_move_dest = false; 
327	                    for(int j=0; j < i; ++j) { 
328	                        if (tentative_move_targets_this_turn[j] == potential_stand_pos) { conflict_with_tentative_move_dest = true; break; }
329	                    }
330	                    if (conflict_with_tentative_move_dest) continue;
331	
332	                    int current_dist_to_stand = manhattan_distance(human.pos, potential_stand_pos);
333	                    int current_eval_score = current_dist_to_stand - adj_wall_bonus_val + current_near_pet_penalty;
334	
335	                    bool is_inside_inner_safe_region = 
336	                        (potential_stand_pos.r >= human.inner_safe_ul.r &&
337	                         potential_stand_pos.r <= human.inner_safe_br.r &&
338	                         potential_stand_pos.c >= human.inner_safe_ul.c &&
339	                         potential_stand_pos.c <= human.inner_safe_br.c);
340	                    
341	                    if (!is_inside_inner_safe_region) {
342	                        current_eval_score += STAND_OUTSIDE_INNER_SAFE_PENALTY; 
343	                    }
344	
345	                    if (current_eval_score < min_eval_score) {
346	                        min_eval_score = current_eval_score;
347	                        best_wall_target = wall_coord;
348	                        best_stand_point = potential_stand_pos;
349	                    } else if (current_eval_score == min_eval_score) { 
350	                        if (best_wall_target.r == -1 || 
351	                            wall_coord < best_wall_target ||
352	                            (wall_coord == best_wall_target && potential_stand_pos < best_stand_point)) {
353	                            best_wall_target = wall_coord;
354	                            best_stand_point = potential_stand_pos;
355	                        }
356	                    }
357	                }
358	            }
359	
360	            if (best_wall_target.r != -1) { 
361	                human.turns_stuck_building = 0; 
362	                if (human.pos == best_stand_point) { 
363	                    for(int k_dir=0; k_dir<4; ++k_dir){ 
364	                        if(human.pos.r + DIRS[k_dir].r == best_wall_target.r && 
365	                           human.pos.c + DIRS[k_dir].c == best_wall_target.c){
366	                            chosen_action_for_human_i = DIR_CHARS_BUILD[k_dir];
367	                            break;
368	                        }
369	                    }
370	                } else { 
371	                    chosen_action_for_human_i = get_bfs_move_char(human.pos, best_stand_point, tentative_walls_this_turn);
372	                }
373	            } else { 
374	                if (unbuilt_walls_count > 0) { 
375	                    human.turns_stuck_building++;
376	                }
377	                if (human.pos != human.final_stand_pos) {
378	                    chosen_action_for_human_i = get_bfs_move_char(human.pos, human.final_stand_pos, tentative_walls_this_turn);
379	                } else { 
380	                    chosen_action_for_human_i = '.'; 
381	                }
382	            }
383	        }
384	        
385	        actions_str[i] = chosen_action_for_human_i;
386	        
387	        if (chosen_action_for_human_i != '.' && (chosen_action_for_human_i == 'u' || chosen_action_for_human_i == 'd' || chosen_action_for_human_i == 'l' || chosen_action_for_human_i == 'r')) {
388	            for(int k_dir=0; k_dir<4; ++k_dir) {
389	                if (chosen_action_for_human_i == DIR_CHARS_BUILD[k_dir]) {
390	                    Point built_wall_pos = {human.pos.r + DIRS[k_dir].r, human.pos.c + DIRS[k_dir].c};
391	                    if (is_valid_point(built_wall_pos)) { 
392	                        tentative_walls_this_turn.push_back(built_wall_pos);
393	                    }
394	                    break;
395	                }
396	            }
397	        } else if (chosen_action_for_human_i != '.' && (chosen_action_for_human_i == 'U' || chosen_action_for_human_i == 'D' || chosen_action_for_human_i == 'L' || chosen_action_for_human_i == 'R')) {
398	            for(int k_dir=0; k_dir<4; ++k_dir) {
399	                if (chosen_action_for_human_i == DIR_CHARS_MOVE[k_dir]) {
400	                    Point target_pos = {human.pos.r + DIRS[k_dir].r, human.pos.c + DIRS[k_dir].c};
401	                     if (is_valid_point(target_pos)) { 
402	                        tentative_move_targets_this_turn[i] = target_pos;
403	                     } else {
404	                        actions_str[i] = '.'; 
405	                     }
406	                    break;
407	                }
408	            }
409	        }
410	    }
411	
412	    for (int i = 0; i < M_humans_global; ++i) {
413	        if (actions_str[i] != '.' && (actions_str[i] == 'U' || actions_str[i] == 'D' || actions_str[i] == 'L' || actions_str[i] == 'R')) {
414	            Point target_move_sq = tentative_move_targets_this_turn[i];
415	            if (target_move_sq.r == -1) { 
416	                actions_str[i] = '.';
417	                continue;
418	            }
419	
420	            bool conflict_with_wall = false;
421	            for (const auto& wall_being_built : tentative_walls_this_turn) { 
422	                if (target_move_sq == wall_being_built) {
423	                    conflict_with_wall = true;
424	                    break; 
425	                }
426	            }
427	            if (conflict_with_wall) {
428	                actions_str[i] = '.'; 
429	            } else { 
430	                for (int j = 0; j < i; ++j) { 
431	                    if (actions_str[j] != '.' && (actions_str[j] == 'U' || actions_str[j] == 'D' || actions_str[j] == 'L' || actions_str[j] == 'R') &&
432	                        tentative_move_targets_this_turn[j] == target_move_sq) {
433	                        actions_str[i] = '.'; 
434	                        break;
435	                    }
436	                }
437	            }
438	        }
439	    }
440	    return actions_str;
441	}
