                    r2 = pr; c2 = pc;
                }
                for (int d2 = 0; d2 < 4; d2++) {
                    if (sr + DR[d2] == r2 && sc + DC[d2] == c2) return MOVE_CHAR[d2];
                }
                return '.';
            }
            q.push({nr, nc});
        }
    }
    return '.';
}

std::pair<int,int> find_nearest_safe_cell(int sr, int sc) {
    static bool visited[31][31];
    for (int r = 1; r <= GRID; r++)
        for (int c = 1; c <= GRID; c++) visited[r][c] = false;

    std::queue<std::pair<int,int>> q;
    q.push({sr, sc});
    visited[sr][sc] = true;
    if (safe_zone[sr][sc]) return {sr, sc};

    while (!q.empty()) {
        auto [cr, cc] = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cr + DR[d], nc = cc + DC[d];
            if (!valid(nr, nc) || wall_grid[nr][nc] || visited[nr][nc]) continue;
            visited[nr][nc] = true;
            if (safe_zone[nr][nc]) return {nr, nc};
            q.push({nr, nc});
        }
    }
    return {-1, -1};
}

struct StaircaseResult {
    int area;
    int total_walls;
    std::vector<std::pair<int,int>> walls;
    bool zone[31][31];
};

StaircaseResult compute_staircase(int corner) {
    // corner: 0=TL, 1=TR, 2=BL, 3=BR
    // Transform pet positions based on corner
    // For TL: safe zone is top-left, h[c] = max safe rows in column c, non-increasing
    // We compute in transformed coords then transform back

    auto transform = [&](int r, int c) -> std::pair<int,int> {
        switch(corner) {
            case 0: return {r, c};
            case 1: return {r, GRID + 1 - c};
            case 2: return {GRID + 1 - r, c};
            case 3: return {GRID + 1 - r, GRID + 1 - c};
        }
        return {r, c};
    };

    auto inverse_transform = [&](int r, int c) -> std::pair<int,int> {
        return transform(r, c); // self-inverse for reflections
    };

    // Compute max_h for each column in transformed coords
    int max_h[31];
    for (int c = 1; c <= GRID; c++) max_h[c] = GRID;

    for (auto& pet : pets) {
        auto [tr, tc] = transform(pet.r, pet.c);
        if (tc >= 1 && tc <= GRID) {
            max_h[tc] = std::min(max_h[tc], tr - 1);
        }
    }

    // Compute non-increasing h
    int h[31];
    h[1] = max_h[1];
    for (int c = 2; c <= GRID; c++) {
        h[c] = std::min(h[c-1], max_h[c]);
    }

    // Also try non-increasing from right to left (non-decreasing left to right)
    // and take element-wise max... actually no. Let me try both directions separately.

    int area_lr = 0;
    for (int c = 1; c <= GRID; c++) area_lr += std::max(0, h[c]);

    // Right-to-left non-increasing
    int h2[31];
    h2[GRID] = max_h[GRID];
    for (int c = GRID - 1; c >= 1; c--) {
        h2[c] = std::min(h2[c+1], max_h[c]);
    }
    int area_rl = 0;
    for (int c = 1; c <= GRID; c++) area_rl += std::max(0, h2[c]);

    // Pick better direction
    int* best_h;
    int best_area;
    if (area_lr >= area_rl) {
        best_h = h;
        best_area = area_lr;
    } else {
        best_h = h2;
        best_area = area_rl;
    }

    // Also try by rows (transpose)
    int max_v[31];
    for (int r = 1; r <= GRID; r++) max_v[r] = GRID;
    for (auto& pet : pets) {
        auto [tr, tc] = transform(pet.r, pet.c);
        if (tr >= 1 && tr <= GRID) {
            max_v[tr] = std::min(max_v[tr], tc - 1);
        }
    }

    int v_lr[31];
    v_lr[1] = max_v[1];
    for (int r = 2; r <= GRID; r++) v_lr[r] = std::min(v_lr[r-1], max_v[r]);
    int area_v_lr = 0;
    for (int r = 1; r <= GRID; r++) area_v_lr += std::max(0, v_lr[r]);

    int v_rl[31];
    v_rl[GRID] = max_v[GRID];
    for (int r = GRID - 1; r >= 1; r--) v_rl[r] = std::min(v_rl[r+1], max_v[r]);
    int area_v_rl = 0;
    for (int r = 1; r <= GRID; r++) area_v_rl += std::max(0, v_rl[r]);

    bool use_transpose = false;
    if (area_v_lr > best_area) { best_area = area_v_lr; use_transpose = true; }
    if (area_v_rl > best_area) { best_area = area_v_rl; use_transpose = true; }
    int* best_v = (area_v_lr >= area_v_rl) ? v_lr : v_rl;
    if (use_transpose && area_v_rl > area_v_lr) best_v = v_rl;

    StaircaseResult result;
    result.area = best_area;
    for (int r = 0; r <= GRID; r++)
        for (int c = 0; c <= GRID; c++) result.zone[r][c] = false;

    if (!use_transpose) {
        // Safe zone in transformed coords: (r,c) where r <= best_h[c]
        for (int c = 1; c <= GRID; c++) {
            for (int r = 1; r <= best_h[c]; r++) {
                auto [or2, oc] = inverse_transform(r, c);
                if (valid(or2, oc)) result.zone[or2][oc] = true;
            }
        }

        // Wall cells
        for (int c = 1; c <= GRID; c++) {
            if (best_h[c] > 0 && best_h[c] < GRID) {
                int wr = best_h[c] + 1, wc = c;
                auto [owr, owc] = inverse_transform(wr, wc);
                if (valid(owr, owc)) result.walls.push_back({owr, owc});
            }
        }
        // Step walls
        for (int c = 2; c <= GRID; c++) {
            if (best_h[c] < best_h[c-1]) {
                for (int r = best_h[c] + 1; r <= best_h[c-1]; r++) {
                    // These cells in column c need to be walls (adjacent to safe cells in column c-1)
                    // Wait, the step is between columns c-1 and c.
                    // Safe in col c-1 at row r (since r <= best_h[c-1]), not safe in col c at row r (since r > best_h[c])
                    // (r, c) is adjacent to (r, c-1) which is safe. So (r, c) must be wall.
                    auto [owr, owc] = inverse_transform(r, c);
                    if (valid(owr, owc)) result.walls.push_back({owr, owc});
                }
            }
            if (best_h[c] > best_h[c-1]) {
                // Step up: safe in col c at row r (r <= best_h[c]), not safe in col c-1 at row r (r > best_h[c-1])
                for (int r = best_h[c-1] + 1; r <= best_h[c]; r++) {
                    auto [owr, owc] = inverse_transform(r, c-1);
                    if (valid(owr, owc)) result.walls.push_back({owr, owc});
                }
            }
        }
        // Right edge wall (if safe zone extends to last column)
        // For left-to-right non-increasing, h[GRID] might be > 0
        // The right edge of grid is already boundary, so no wall needed there
        // Similarly for left edge with right-to-left
        // But if h[1] > 0 and we're using right-to-left, we need left wall? No, grid edge handles it.
        // Actually for left-to-right non-increasing: leftmost column's right boundary is handled by the step logic
        // And grid edges handle the actual left/top boundaries.

    } else {
        // Transpose version: safe zone (r,c) where c <= best_v[r]
        for (int r = 1; r <= GRID; r++) {
            for (int c = 1; c <= best_v[r]; c++) {
                auto [or2, oc] = inverse_transform(r, c);
                if (valid(or2, oc)) result.zone[or2][oc] = true;
            }
        }

        // Wall cells - right boundary
        for (int r = 1; r <= GRID; r++) {
            if (best_v[r] > 0 && best_v[r] < GRID) {
                int wr = r, wc = best_v[r] + 1;
                auto [owr, owc] = inverse_transform(wr, wc);
                if (valid(owr, owc)) result.walls.push_back({owr, owc});
            }
        }
        // Step walls between rows
        for (int r = 2; r <= GRID; r++) {
            if (best_v[r] < best_v[r-1]) {
                for (int c = best_v[r] + 1; c <= best_v[r-1]; c++) {
                    auto [owr, owc] = inverse_transform(r, c);
                    if (valid(owr, owc)) result.walls.push_back({owr, owc});
                }
            }
            if (best_v[r] > best_v[r-1]) {
                for (int c = best_v[r-1] + 1; c <= best_v[r]; c++) {
                    auto [owr, owc] = inverse_transform(r-1, c);
                    if (valid(owr, owc)) result.walls.push_back({owr, owc});
                }
            }
        }
    }

    result.total_walls = result.walls.size();

    // Remove duplicates
    std::sort(result.walls.begin(), result.walls.end());
    result.walls.erase(std::unique(result.walls.begin(), result.walls.end()), result.walls.end());
    result.total_walls = result.walls.size();

    return result;
}

