#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>

constexpr int GRID = 30;
constexpr int TURNS = 300;
const int DR[] = {-1, 1, 0, 0};
const int DC[] = {0, 0, -1, 1};
const char BUILD_CHAR[] = {'u', 'd', 'l', 'r'};
const char MOVE_CHAR[] = {'U', 'D', 'L', 'R'};

struct Pet { int r, c, type; };
struct Human { int r, c; };

int N, M;
std::vector<Pet> pets;
std::vector<Human> humans;
bool wall_grid[31][31];
bool safe_zone[31][31];
std::vector<std::pair<int,int>> wall_cells;
bool wall_built[31][31];

bool valid(int r, int c) { return r >= 1 && r <= GRID && c >= 1 && c <= GRID; }

bool pet_at_or_adjacent(int r, int c) {
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return true;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return true;
    }
    return false;
}

bool human_at(int r, int c, int exclude = -1) {
    for (int i = 0; i < M; i++) {
        if (i == exclude) continue;
        if (humans[i].r == r && humans[i].c == c) return true;
    }
    return false;
}

char bfs_move(int sr, int sc, int tr, int tc, bool avoid_walls_being_built = false) {
    if (sr == tr && sc == tc) return '.';
    static bool visited[31][31];
    static std::pair<int,int> parent[31][31];
    for (int r = 1; r <= GRID; r++)
        for (int c = 1; c <= GRID; c++) {
            visited[r][c] = false;
            parent[r][c] = {-1, -1};
        }

    std::queue<std::pair<int,int>> q;
    q.push({sr, sc});
    visited[sr][sc] = true;

    while (!q.empty()) {
        auto [cr, cc] = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cr + DR[d], nc = cc + DC[d];
            if (!valid(nr, nc) || wall_grid[nr][nc] || visited[nr][nc]) continue;
            if (avoid_walls_being_built && wall_built[nr][nc] == false) {
                bool is_wall_cell = false;
                for (auto& wc : wall_cells) {
                    if (wc.first == nr && wc.second == nc) { is_wall_cell = true; break; }
                }
                if (is_wall_cell) continue;
            }
            visited[nr][nc] = true;
            parent[nr][nc] = {cr, cc};
            if (nr == tr && nc == tc) {
                int r2 = nr, c2 = nc;
                while (!(parent[r2][c2].first == sr && parent[r2][c2].second == sc)) {
                    auto [pr, pc] = parent[r2][c2];
                    r2 = pr; c2 = pc;
                }
                for (int d2 = 0; d2 < 4; d2++) {
                    if (sr + DR[d2] == r2 && sc + DC[d2] == c2) return MOVE_CHAR[d2];
                }
                return '.';
            }
            q.push({nr, nc});
        }
    }
    return '.';
}

std::pair<int,int> find_nearest_safe_cell(int sr, int sc) {
    static bool visited[31][31];
    for (int r = 1; r <= GRID; r++)
        for (int c = 1; c <= GRID; c++) visited[r][c] = false;

    std::queue<std::pair<int,int>> q;
    q.push({sr, sc});
    visited[sr][sc] = true;
    if (safe_zone[sr][sc]) return {sr, sc};

    while (!q.empty()) {
        auto [cr, cc] = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cr + DR[d], nc = cc + DC[d];
            if (!valid(nr, nc) || wall_grid[nr][nc] || visited[nr][nc]) continue;
            visited[nr][nc] = true;
            if (safe_zone[nr][nc]) return {nr, nc};
            q.push({nr, nc});
        }
    }
    return {-1, -1};
}

struct StaircaseResult {
    int area;
    int total_walls;
    std::vector<std::pair<int,int>> walls;
    bool zone[31][31];
};

StaircaseResult compute_staircase(int corner) {
    // corner: 0=TL, 1=TR, 2=BL, 3=BR
    // Transform pet positions based on corner
    // For TL: safe zone is top-left, h[c] = max safe rows in column c, non-increasing
    // We compute in transformed coords then transform back

    auto transform = [&](int r, int c) -> std::pair<int,int> {
        switch(corner) {
            case 0: return {r, c};
            case 1: return {r, GRID + 1 - c};
            case 2: return {GRID + 1 - r, c};
            case 3: return {GRID + 1 - r, GRID + 1 - c};
        }
        return {r, c};
    };

    auto inverse_transform = [&](int r, int c) -> std::pair<int,int> {
        return transform(r, c); // self-inverse for reflections
    };

    // Compute max_h for each column in transformed coords
    int max_h[31];
    for (int c = 1; c <= GRID; c++) max_h[c] = GRID;

    for (auto& pet : pets) {
        auto [tr, tc] = transform(pet.r, pet.c);
        if (tc >= 1 && tc <= GRID) {
            max_h[tc] = std::min(max_h[tc], tr - 1);
        }
    }

    // Compute non-increasing h
    int h[31];
    h[1] = max_h[1];
    for (int c = 2; c <= GRID; c++) {
        h[c] = std::min(h[c-1], max_h[c]);
    }

    // Also try non-increasing from right to left (non-decreasing left to right)
    // and take element-wise max... actually no. Let me try both directions separately.

    int area_lr = 0;
    for (int c = 1; c <= GRID; c++) area_lr += std::max(0, h[c]);

    // Right-to-left non-increasing
    int h2[31];
    h2[GRID] = max_h[GRID];
    for (int c = GRID - 1; c >= 1; c--) {
        h2[c] = std::min(h2[c+1], max_h[c]);
    }
    int area_rl = 0;
    for (int c = 1; c <= GRID; c++) area_rl += std::max(0, h2[c]);

    // Pick better direction
    int* best_h;
    int best_area;
    if (area_lr >= area_rl) {
        best_h = h;
        best_area = area_lr;
    } else {
        best_h = h2;
        best_area = area_rl;
    }

    // Also try by rows (transpose)
    int max_v[31];
    for (int r = 1; r <= GRID; r++) max_v[r] = GRID;
    for (auto& pet : pets) {
        auto [tr, tc] = transform(pet.r, pet.c);
        if (tr >= 1 && tr <= GRID) {
            max_v[tr] = std::min(max_v[tr], tc - 1);
        }
    }

    int v_lr[31];
    v_lr[1] = max_v[1];
    for (int r = 2; r <= GRID; r++) v_lr[r] = std::min(v_lr[r-1], max_v[r]);
    int area_v_lr = 0;
    for (int r = 1; r <= GRID; r++) area_v_lr += std::max(0, v_lr[r]);

    int v_rl[31];
    v_rl[GRID] = max_v[GRID];
    for (int r = GRID - 1; r >= 1; r--) v_rl[r] = std::min(v_rl[r+1], max_v[r]);
    int area_v_rl = 0;
    for (int r = 1; r <= GRID; r++) area_v_rl += std::max(0, v_rl[r]);

    bool use_transpose = false;
    if (area_v_lr > best_area) { best_area = area_v_lr; use_transpose = true; }
    if (area_v_rl > best_area) { best_area = area_v_rl; use_transpose = true; }
    int* best_v = (area_v_lr >= area_v_rl) ? v_lr : v_rl;
    if (use_transpose && area_v_rl > area_v_lr) best_v = v_rl;

    StaircaseResult result;
    result.area = best_area;
    for (int r = 0; r <= GRID; r++)
        for (int c = 0; c <= GRID; c++) result.zone[r][c] = false;

    if (!use_transpose) {
        // Safe zone in transformed coords: (r,c) where r <= best_h[c]
        for (int c = 1; c <= GRID; c++) {
            for (int r = 1; r <= best_h[c]; r++) {
                auto [or2, oc] = inverse_transform(r, c);
                if (valid(or2, oc)) result.zone[or2][oc] = true;
            }
        }

        // Wall cells
        for (int c = 1; c <= GRID; c++) {
            if (best_h[c] > 0 && best_h[c] < GRID) {
                int wr = best_h[c] + 1, wc = c;
                auto [owr, owc] = inverse_transform(wr, wc);
                if (valid(owr, owc)) result.walls.push_back({owr, owc});
            }
        }
        // Step walls
        for (int c = 2; c <= GRID; c++) {
            if (best_h[c] < best_h[c-1]) {
                for (int r = best_h[c] + 1; r <= best_h[c-1]; r++) {
                    // These cells in column c need to be walls (adjacent to safe cells in column c-1)
                    // Wait, the step is between columns c-1 and c.
                    // Safe in col c-1 at row r (since r <= best_h[c-1]), not safe in col c at row r (since r > best_h[c])
                    // (r, c) is adjacent to (r, c-1) which is safe. So (r, c) must be wall.
                    auto [owr, owc] = inverse_transform(r, c);
                    if (valid(owr, owc)) result.walls.push_back({owr, owc});
                }
            }
            if (best_h[c] > best_h[c-1]) {
                // Step up: safe in col c at row r (r <= best_h[c]), not safe in col c-1 at row r (r > best_h[c-1])
                for (int r = best_h[c-1] + 1; r <= best_h[c]; r++) {
                    auto [owr, owc] = inverse_transform(r, c-1);
                    if (valid(owr, owc)) result.walls.push_back({owr, owc});
                }
            }
        }
        // Right edge wall (if safe zone extends to last column)
        // For left-to-right non-increasing, h[GRID] might be > 0
        // The right edge of grid is already boundary, so no wall needed there
        // Similarly for left edge with right-to-left
        // But if h[1] > 0 and we're using right-to-left, we need left wall? No, grid edge handles it.
        // Actually for left-to-right non-increasing: leftmost column's right boundary is handled by the step logic
        // And grid edges handle the actual left/top boundaries.

    } else {
        // Transpose version: safe zone (r,c) where c <= best_v[r]
        for (int r = 1; r <= GRID; r++) {
            for (int c = 1; c <= best_v[r]; c++) {
                auto [or2, oc] = inverse_transform(r, c);
                if (valid(or2, oc)) result.zone[or2][oc] = true;
            }
        }

        // Wall cells - right boundary
        for (int r = 1; r <= GRID; r++) {
            if (best_v[r] > 0 && best_v[r] < GRID) {
                int wr = r, wc = best_v[r] + 1;
                auto [owr, owc] = inverse_transform(wr, wc);
                if (valid(owr, owc)) result.walls.push_back({owr, owc});
            }
        }
        // Step walls between rows
        for (int r = 2; r <= GRID; r++) {
            if (best_v[r] < best_v[r-1]) {
                for (int c = best_v[r] + 1; c <= best_v[r-1]; c++) {
                    auto [owr, owc] = inverse_transform(r, c);
                    if (valid(owr, owc)) result.walls.push_back({owr, owc});
                }
            }
            if (best_v[r] > best_v[r-1]) {
                for (int c = best_v[r-1] + 1; c <= best_v[r]; c++) {
                    auto [owr, owc] = inverse_transform(r-1, c);
                    if (valid(owr, owc)) result.walls.push_back({owr, owc});
                }
            }
        }
    }

    result.total_walls = result.walls.size();

    // Remove duplicates
    std::sort(result.walls.begin(), result.walls.end());
    result.walls.erase(std::unique(result.walls.begin(), result.walls.end()), result.walls.end());
    result.total_walls = result.walls.size();

    return result;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pets[i].type;
    }
    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }

    for (int r = 0; r <= GRID; r++)
        for (int c = 0; c <= GRID; c++) {
            wall_grid[r][c] = false;
            wall_built[r][c] = false;
        }

    // Find best staircase across all corners
    StaircaseResult best;
    best.area = 0;

    for (int corner = 0; corner < 4; corner++) {
        StaircaseResult res = compute_staircase(corner);
        if (res.area > best.area) {
            best = res;
        }
    }

    // Set safe zone
    for (int r = 1; r <= GRID; r++)
        for (int c = 1; c <= GRID; c++)
            safe_zone[r][c] = best.zone[r][c];

    // Wall cells to build
    wall_cells = best.walls;

    // Remove wall cells that are already at grid boundary (they're already impassable effectively)
    // Actually grid boundary cells (outside 1-30) are impassable, not cells at row 1/30.
    // Cells at row 1, col 1 etc are valid cells. So we keep all wall cells.

    // Sort wall cells by priority: those closest to any pet first (seal gaps near pets ASAP)
    std::sort(wall_cells.begin(), wall_cells.end(), [&](auto& a, auto& b) {
        int min_dist_a = 999, min_dist_b = 999;
        for (auto& p : pets) {
            min_dist_a = std::min(min_dist_a, std::abs(p.r - a.first) + std::abs(p.c - a.second));
            min_dist_b = std::min(min_dist_b, std::abs(p.r - b.first) + std::abs(p.c - b.second));
        }
        return min_dist_a < min_dist_b;
    });

    // Main game loop
    for (int turn = 0; turn < TURNS; turn++) {
        std::string actions(M, '.');

        // Track which wall cells are planned to be built this turn
        std::vector<std::pair<int,int>> planned_builds;

        for (int i = 0; i < M; i++) {
            int hr = humans[i].r, hc = humans[i].c;

            // Check if human is in safe zone
            bool in_safe = safe_zone[hr][hc];

            if (!in_safe) {
                // Move toward safe zone
                auto [tr, tc] = find_nearest_safe_cell(hr, hc);
                if (tr != -1) {
                    char mv = bfs_move(hr, hc, tr, tc);
                    if (mv != '.') {
                        actions[i] = mv;
                        continue;
                    }
                }
                actions[i] = '.';
                continue;
            }

            // Human is in safe zone - try to build a wall
            // Find nearest unbuilt wall cell adjacent to human
            int best_dir = -1;
            int best_wall_idx = -1;
            int best_priority = 999999;

            for (int d = 0; d < 4; d++) {
                int wr = hr + DR[d], wc = hc + DC[d];
                if (!valid(wr, wc)) continue;
                if (wall_grid[wr][wc]) continue; // already built

                // Check if this is a wall cell we need to build
                bool is_needed = false;
                int widx = -1;
                for (int wi = 0; wi < (int)wall_cells.size(); wi++) {
                    if (wall_cells[wi].first == wr && wall_cells[wi].second == wc) {
                        is_needed = true;
                        widx = wi;
                        break;
                    }
                }
                if (!is_needed) continue;

                // Check if already planned by another human this turn
                bool already_planned = false;
                for (auto& pb : planned_builds) {
                    if (pb.first == wr && pb.second == wc) { already_planned = true; break; }
                }
                if (already_planned) continue;

                // Check pet adjacency constraint
                if (pet_at_or_adjacent(wr, wc)) continue;

                // Check no human or pet ON the wall cell
                bool occupied = false;
                for (int j = 0; j < M; j++) {
                    if (j == i) continue;
                    if (humans[j].r == wr && humans[j].c == wc) { occupied = true; break; }
                }
                if (occupied) continue;

                if (widx < best_priority) {
                    best_priority = widx;
                    best_dir = d;
                    best_wall_idx = widx;
                }
            }

            if (best_dir != -1) {
                actions[i] = BUILD_CHAR[best_dir];
                int wr = hr + DR[best_dir], wc = hc + DC[best_dir];
                planned_builds.push_back({wr, wc});
                continue;
            }

            // Not adjacent to any buildable wall cell - move toward one
            // Find nearest unbuilt wall cell and move to an adjacent safe cell
            int min_dist = 999999;
            int target_r = -1, target_c = -1;

            for (auto& wc_pair : wall_cells) {
                int wr = wc_pair.first, wcc = wc_pair.second;
                if (wall_grid[wr][wcc]) continue; // already built

                // Find adjacent safe cell to stand on while building this wall
                for (int d = 0; d < 4; d++) {
                    int sr = wr + DR[d], sc = wcc + DC[d];
                    if (!valid(sr, sc)) continue;
                    if (!safe_zone[sr][sc]) continue;
                    if (wall_grid[sr][sc]) continue;

                    int dist = std::abs(hr - sr) + std::abs(hc - sc);
                    if (dist < min_dist) {
                        min_dist = dist;
                        target_r = sr;
                        target_c = sc;
                    }
                }
            }

            if (target_r != -1 && min_dist > 0) {
                char mv = bfs_move(hr, hc, target_r, target_c);
                actions[i] = mv;
            } else {
                actions[i] = '.';
            }
        }

        // Output actions
        std::cout << actions << std::endl;

        // Apply build actions to our grid
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            for (int d = 0; d < 4; d++) {
                if (a == BUILD_CHAR[d]) {
                    int wr = humans[i].r + DR[d], wc = humans[i].c + DC[d];
                    if (valid(wr, wc)) {
                        wall_grid[wr][wc] = true;
                        wall_built[wr][wc] = true;
                    }
                    break;
                }
            }
            for (int d = 0; d < 4; d++) {
                if (a == MOVE_CHAR[d]) {
                    int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                    if (valid(nr, nc) && !wall_grid[nr][nc]) {
                        humans[i].r = nr;
                        humans[i].c = nc;
                    }
                    break;
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string mv;
            std::cin >> mv;
            if (mv == ".") continue;
            for (char ch : mv) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CHAR[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
