# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>

constexpr int GRID = 30;
constexpr int TURNS = 300;
const int DR[] = {-1, 1, 0, 0};
const int DC[] = {0, 0, -1, 1};
const char BUILD_CHAR[] = {'u', 'd', 'l', 'r'};
const char MOVE_CHAR[] = {'U', 'D', 'L', 'R'};

struct Pet { int r, c, type; };
struct Human { int r, c; };

int N, M;
std::vector<Pet> pets;
std::vector<Human> humans;
bool wall_grid[31][31];

bool valid(int r, int c) { return r >= 1 && r <= GRID && c >= 1 && c <= GRID; }

bool pet_at_or_adjacent(int r, int c) {
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return true;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return true;
    }
    return false;
}

char bfs_move(int sr, int sc, int tr, int tc) {
    if (sr == tr && sc == tc) return '.';
    static bool visited[31][31];
    static std::pair<int,int> parent[31][31];
    for (int r = 1; r <= GRID; r++)
        for (int c = 1; c <= GRID; c++) {
            visited[r][c] = false;
            parent[r][c] = {-1, -1};
        }

    std::queue<std::pair<int,int>> q;
    q.push({sr, sc});
    visited[sr][sc] = true;

    while (!q.empty()) {
        auto [cr, cc] = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cr + DR[d], nc = cc + DC[d];
            if (!valid(nr, nc) || wall_grid[nr][nc] || visited[nr][nc]) continue;
            visited[nr][nc] = true;
            parent[nr][nc] = {cr, cc};
            if (nr == tr && nc == tc) {
                int r2 = nr, c2 = nc;
                while (!(parent[r2][c2].first == sr && parent[r2][c2].second == sc)) {
                    auto [pr, pc] = parent[r2][c2];
                    r2 = pr; c2 = pc;
                }
                for (int d2 = 0; d2 < 4; d2++) {
                    if (sr + DR[d2] == r2 && sc + DC[d2] == c2) return MOVE_CHAR[d2];
                }
                return '.';
            }
            q.push({nr, nc});
        }
    }
    return '.';
}

// Compute BFS distance
int bfs_dist(int sr, int sc, int tr, int tc) {
    if (sr == tr && sc == tc) return 0;
    static bool visited[31][31];
    for (int r = 1; r <= GRID; r++)
        for (int c = 1; c <= GRID; c++) visited[r][c] = false;
    std::queue<std::pair<int,int>> q;
    q.push({sr, sc});
    visited[sr][sc] = true;
    static int dist[31][31];
    dist[sr][sc] = 0;
    while (!q.empty()) {
        auto [cr, cc] = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cr + DR[d], nc = cc + DC[d];
            if (!valid(nr, nc) || wall_grid[nr][nc] || visited[nr][nc]) continue;
            visited[nr][nc] = true;
            dist[nr][nc] = dist[cr][cc] + 1;
            if (nr == tr && nc == tc) return dist[nr][nc];
            q.push({nr, nc});
        }
    }
    return 999999;
}

struct Rect {
    int r1, c1, r2, c2; // interior region (safe zone)
    // Wall is on the border cells that are NOT at grid edge
    std::vector<std::pair<int,int>> walls;
    int area;
};

Rect compute_rect(int r1, int c1, int r2, int c2) {
    // Interior is [r1..r2] x [c1..c2]
    // Walls needed are cells adjacent to interior that aren't grid boundary
    Rect rect;
    rect.r1 = r1; rect.c1 = c1; rect.r2 = r2; rect.c2 = c2;
    rect.area = (r2 - r1 + 1) * (c2 - c1 + 1);

    // Top wall row (r1-1), if r1 > 1
    if (r1 > 1) {
        for (int c = c1; c <= c2; c++) rect.walls.push_back({r1-1, c});
    }
    // Bottom wall row (r2+1), if r2 < GRID
    if (r2 < GRID) {
        for (int c = c1; c <= c2; c++) rect.walls.push_back({r2+1, c});
    }
    // Left wall col (c1-1), if c1 > 1
    if (c1 > 1) {
        for (int r = r1; r <= r2; r++) rect.walls.push_back({r, c1-1});
    }
    // Right wall col (c2+1), if c2 < GRID
    if (c2 < GRID) {
        for (int r = r1; r <= r2; r++) rect.walls.push_back({r, c2+1});
    }
    // Corners
    if (r1 > 1 && c1 > 1) rect.walls.push_back({r1-1, c1-1});
    if (r1 > 1 && c2 < GRID) rect.walls.push_back({r1-1, c2+1});
    if (r2 < GRID && c1 > 1) rect.walls.push_back({r2+1, c1-1});
    if (r2 < GRID && c2 < GRID) rect.walls.push_back({r2+1, c2+1});

    std::sort(rect.walls.begin(), rect.walls.end());
    rect.walls.erase(std::unique(rect.walls.begin(), rect.walls.end()), rect.walls.end());
    return rect;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pets[i].type;
    }
    std::cin >> M;
    humans.resize(M);
    for (int i = 0; i < M; i++) {
        std::cin >> humans[i].r >> humans[i].c;
    }

    for (int r = 0; r <= GRID; r++)
        for (int c = 0; c <= GRID; c++) wall_grid[r][c] = false;

    // Strategy: Each human builds their own small rectangular enclosure in a corner/edge.
    // The rectangle is positioned to be far from pets and uses grid edges as walls.
    // The human needs to be INSIDE the rectangle when done.

    // Alternative strategy: find the best single rectangle that all humans can collaborate to build.
    // The rectangle should be in a corner (leveraging 2 edges) or edge (1 edge) to minimize walls.
    // All humans move to the interior, then build the wall from inside.

    // Let's try: each human gets their own small rectangle in a corner/edge position.
    // Budget per human: ~300/M turns to build + move. With M=5-10, each gets 30-60 effective turns.
    // A rectangle using 2 grid edges (corner) needs 2 sides of walls.
    // For a WxH rectangle in corner: walls = W + H cells (minus shared corner cell if both walls)
    // Actually: interior WxH, walls are W cells on one side + H cells on other side = W+H cells

    // Better: find the best rectangle for EACH human individually (closest corner, max area given wall budget)
    // Budget: each human can build about 1 wall per 2-3 turns (move + build).
    // With 300 turns and needing to reach the build site, effective budget ~ 100 wall cells per human.
    // Actually much less - need to reach the site first.

    // Simpler approach: Two horizontal walls strategy but with variable width.
    // Let me instead try collaborative rectangle: pick the best corner, all humans move there and build together.

    // For a corner rectangle using top-left corner:
    // Interior = [1..H] x [1..W]
    // Walls needed: row H+1 from col 1 to W (W cells) + col W+1 from row 1 to H (H cells) + corner (H+1, W+1) = W + H + 1 cells
    // Area = W * H
    // Total walls buildable = M * (300 - travel_time) / 2 roughly

    // Try all 4 corners with various sizes
    struct Plan {
        Rect rect;
        int corner; // 0=TL, 1=TR, 2=BL, 3=BR
        double score;
    };

    std::vector<Plan> plans;

    // For each corner, find the largest rectangle that:
    // 1. Has no pets initially inside
    // 2. Wall count is feasible (we can build it in time)
    // 3. Maximize area

    auto try_corner_rect = [&](int corner) {
        // Try various W, H for this corner
        for (int W = 5; W <= 28; W++) {
            for (int H = 5; H <= 28; H++) {
                int r1, c1, r2, c2;
                switch (corner) {
                    case 0: r1=1; c1=1; r2=H; c2=W; break;
                    case 1: r1=1; c1=GRID-W+1; r2=H; c2=GRID; break;
                    case 2: r1=GRID-H+1; c1=1; r2=GRID; c2=W; break;
                    case 3: r1=GRID-H+1; c1=GRID-W+1; r2=GRID; c2=GRID; break;
                    default: continue;
                }

                // Check no pets inside
                bool has_pet = false;
                for (auto& p : pets) {
                    if (p.r >= r1 && p.r <= r2 && p.c >= c1 && p.c <= c2) {
                        has_pet = true;
                        break;
                    }
                }
                if (has_pet) continue;

                Rect rect = compute_rect(r1, c1, r2, c2);
                int n_walls = rect.walls.size();

                // Estimate time: humans need to travel to the rect + build walls
                // Each human can build ~1 wall every 2 turns (accounting for repositioning)
                // Total wall capacity: M * TURNS / 2 = M * 150
                // But humans need to travel first. Estimate avg travel = 15 turns per human.
                // Effective capacity: M * (TURNS - 15) / 2
                int effective_capacity = M * (TURNS - 20) / 2;
                if (n_walls > effective_capacity) continue;

                // Estimate minimum pet distance to the wall
                int min_pet_dist = 999;
                for (auto& p : pets) {
                    for (auto& w : rect.walls) {
                        int d = std::abs(p.r - w.first) + std::abs(p.c - w.second);
                        min_pet_dist = std::min(min_pet_dist, d);
                    }
                }

                // Score: area, penalized if walls are close to pets
                double score = (double)rect.area;
                if (min_pet_dist < 3) score *= 0.5; // Pets very close to wall

                Plan plan;
                plan.rect = rect;
                plan.corner = corner;
                plan.score = score;
                plans.push_back(plan);
            }
        }
    };

    for (int c = 0; c < 4; c++) try_corner_rect(c);

    // Sort by score descending
    std::sort(plans.begin(), plans.end(), [](const Plan& a, const Plan& b) {
        return a.score > b.score;
    });

    // Pick best plan
    Rect chosen;
    if (!plans.empty()) {
        chosen = plans[0].rect;
    } else {
        // Fallback: small rectangle in TL corner
        chosen = compute_rect(1, 1, 5, 5);
    }

    // Wall cells to build
    std::vector<std::pair<int,int>> wall_cells = chosen.walls;

    // Assign humans to wall cells in round-robin by proximity
    // Each human builds walls nearest to them
    std::vector<std::vector<int>> human_wall_assignments(M);
    std::vector<bool> wall_assigned(wall_cells.size(), false);

    // First, sort wall cells for building order: prioritize sealing from one end
    // Build from both ends toward middle to seal faster

    // Simple approach: assign each wall cell to nearest available human
    for (int w = 0; w < (int)wall_cells.size(); w++) {
        int best_h = -1;
        int best_dist = 999999;
        int min_assigned = 999999;
        for (int h = 0; h < M; h++) {
            min_assigned = std::min(min_assigned, (int)human_wall_assignments[h].size());
        }
        for (int h = 0; h < M; h++) {
            if ((int)human_wall_assignments[h].size() > min_assigned + 5) continue;
            int d = std::abs(humans[h].r - wall_cells[w].first) + std::abs(humans[h].c - wall_cells[w].second);
            if (d < best_dist) {
                best_dist = d;
                best_h = h;
            }
        }
        if (best_h >= 0) human_wall_assignments[best_h].push_back(w);
    }

    // Each human's target: go to safe zone, then build assigned walls from inside
    // Human phases:
    // 1. Move to interior of rectangle
    // 2. Build assigned wall cells (move to adjacent interior cell, build outward)

