constexpr int GRID = 30;
constexpr int TURNS = 300;
const int DR[] = {-1, 1, 0, 0};
const int DC[] = {0, 0, -1, 1};
const char BUILD_CHAR[] = {'u', 'd', 'l', 'r'};
const char MOVE_CHAR[] = {'U', 'D', 'L', 'R'};

int N, M;
struct Pet { int r, c, type; };
struct Human { int r, c; };
std::vector<Pet> pets;
std::vector<Human> humans;
bool wall[31][31];

bool valid(int r, int c) { return r >= 1 && r <= GRID && c >= 1 && c <= GRID; }

bool pet_on_or_adj(int r, int c) {
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return true;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return true;
    }
    return false;
}

// BFS to find shortest path from (sr,sc) to (tr,tc) avoiding walls
char bfs_move(int sr, int sc, int tr, int tc) {
    if (sr == tr && sc == tc) return '.';
    static bool vis[31][31];
    static int par_d[31][31]; // direction used to reach this cell
    for (int r = 1; r <= GRID; r++)
        for (int c = 1; c <= GRID; c++) vis[r][c] = false;

    struct Node { int r, c; };
    std::queue<Node> q;
    q.push({sr, sc});
    vis[sr][sc] = true;

    static std::pair<int,int> parent[31][31];
    parent[sr][sc] = {-1,-1};

    while (!q.empty()) {
        auto [cr, cc] = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cr + DR[d], nc = cc + DC[d];
            if (!valid(nr, nc) || wall[nr][nc] || vis[nr][nc]) continue;
            vis[nr][nc] = true;
            parent[nr][nc] = {cr, cc};
            if (nr == tr && nc == tc) {
                // Trace back to find first step
                int r2 = nr, c2 = nc;
                while (!(parent[r2][c2].first == sr && parent[r2][c2].second == sc)) {
                    auto [pr, pc] = parent[r2][c2];
                    r2 = pr; c2 = pc;
                }
                for (int d2 = 0; d2 < 4; d2++) {
                    if (sr + DR[d2] == r2 && sc + DC[d2] == c2) return MOVE_CHAR[d2];
                }
                return '.';
            }
            q.push({nr, nc});
        }
    }
    return '.';
}

// Flood fill to count reachable cells from (sr,sc)
int flood_fill_count(int sr, int sc) {
    static bool vis[31][31];
    for (int r = 1; r <= GRID; r++)
        for (int c = 1; c <= GRID; c++) vis[r][c] = false;
    std::queue<std::pair<int,int>> q;
    q.push({sr, sc});
    vis[sr][sc] = true;
    int count = 1;
    while (!q.empty()) {
        auto [cr, cc] = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cr + DR[d], nc = cc + DC[d];
            if (!valid(nr, nc) || wall[nr][nc] || vis[nr][nc]) continue;
