    for (int i = 0; i < M; i++) std::cin >> humans[i].r >> humans[i].c;

    for (int r = 0; r <= GRID; r++)
        for (int c = 0; c <= GRID; c++) wall[r][c] = false;

    // Strategy: Each human moves toward a designated target position (in a grid-edge corner region),
    // then builds walls around themselves to create a sealed room.
    // Each human targets a different position spread along the grid edges.

    // Assign each human a target position at a grid corner/edge that maximizes distance from pets.
    // Target positions are spread along the perimeter.
    // Each human will build a 3x3 or larger room around themselves using the grid edge.

    // Actually, let's try a different radical approach:
    // "Flee and seal" - each human runs away from all pets to a corner/edge,
    // then builds walls to seal themselves in a pet-free zone.
    // The key insight: humans just need to be in a connected passable area with no pets.
    // If a human can seal themselves in even a SMALL room, they get area/900 * 2^0 = area/900.
    // A 5x5 room gives 25/900 = 0.028. A 10x10 room gives 100/900 = 0.111.
    // But if ALL M humans share one large room, they each get the full area.
    // So the optimal strategy is ONE large shared room for all humans.

    // Let's go with: collaborative L-shaped or rectangular enclosure in the pet-free corner.
    // Key fix from before: humans must NEVER try to move into walls.

    // Find the corner with maximum distance from all pets (sum of distances)
    int corners[4][2] = {{1,1}, {1,GRID}, {GRID,1}, {GRID,GRID}};
    int best_corner = 0;
    int best_min_pet_dist = 0;
    for (int ci = 0; ci < 4; ci++) {
        int min_d = 999;
        for (auto& p : pets) {
            int d = std::abs(p.r - corners[ci][0]) + std::abs(p.c - corners[ci][1]);
            min_d = std::min(min_d, d);
        }
        if (min_d > best_min_pet_dist) {
            best_min_pet_dist = min_d;
            best_corner = ci;
        }
    }

    // Determine rectangle dimensions using this corner.
    // We want the largest rectangle that has no pets inside and feasible wall count.
    // Corner rectangle: interior [r1..r2] x [c1..c2], walls on the 2 non-edge sides.
    int best_area = 0;
    int best_r1, best_c1, best_r2, best_c2;
    best_r1 = best_c1 = best_r2 = best_c2 = 0;

    auto try_size = [&](int corner, int H, int W) {
        int r1, c1, r2, c2;
        switch (corner) {
            case 0: r1=1; c1=1; r2=H; c2=W; break;
            case 1: r1=1; c1=GRID-W+1; r2=H; c2=GRID; break;
            case 2: r1=GRID-H+1; c1=1; r2=GRID; c2=W; break;
            case 3: r1=GRID-H+1; c1=GRID-W+1; r2=GRID; c2=GRID; break;
            default: return;
        }

        // Check no pets inside or on the wall line
        for (auto& p : pets) {
            // Pet inside interior
            if (p.r >= r1 && p.r <= r2 && p.c >= c1 && p.c <= c2) return;
            // Pet on wall line (need 2 distance from wall)
            // Actually just check if pet is inside. Pets on walls will be handled dynamically.
        }

        // Count walls needed (non-edge sides)
        int n_walls = 0;
        // For corner 0 (TL): walls on row H+1 (cols 1..W) and col W+1 (rows 1..H) + corner
        // General: walls on the boundary cells adjacent to interior that aren't grid-edge
        if (r1 > 1) n_walls += (c2 - c1 + 1); // top wall row
        if (r2 < GRID) n_walls += (c2 - c1 + 1); // bottom wall row
        if (c1 > 1) n_walls += (r2 - r1 + 1); // left wall col
        if (c2 < GRID) n_walls += (r2 - r1 + 1); // right wall col
        // Corner cells
        if (r1 > 1 && c1 > 1) n_walls++;
        if (r1 > 1 && c2 < GRID) n_walls++;
        if (r2 < GRID && c1 > 1) n_walls++;
        if (r2 < GRID && c2 < GRID) n_walls++;

        // Check feasibility: M humans, each building 1 wall per ~2 turns (move + build)
        // Account for travel time (~20 turns) and need to build from inside
        int build_budget = M * (TURNS - 30) / 2;
        if (n_walls > build_budget) return;

        int area = (r2 - r1 + 1) * (c2 - c1 + 1);
        if (area > best_area) {
            best_area = area;
            best_r1 = r1; best_c1 = c1; best_r2 = r2; best_c2 = c2;
        }
    };

    // Try sizes for the best corner
    for (int H = 3; H <= 29; H++) {
        for (int W = 3; W <= 29; W++) {
            try_size(best_corner, H, W);
        }
    }

    // Also try all 4 corners to find better option
    for (int ci = 0; ci < 4; ci++) {
        if (ci == best_corner) continue;
        for (int H = 3; H <= 29; H++) {
            for (int W = 3; W <= 29; W++) {
                try_size(ci, H, W);
            }
        }
    }

    int r1 = best_r1, c1 = best_c1, r2 = best_r2, c2 = best_c2;

    // Compute wall cells
    std::vector<std::pair<int,int>> wall_cells;
    if (r1 > 1) for (int c = c1; c <= c2; c++) wall_cells.push_back({r1-1, c});
    if (r2 < GRID) for (int c = c1; c <= c2; c++) wall_cells.push_back({r2+1, c});
    if (c1 > 1) for (int r = r1; r <= r2; r++) wall_cells.push_back({r, c1-1});
    if (c2 < GRID) for (int r = r1; r <= r2; r++) wall_cells.push_back({r, c2+1});
    if (r1 > 1 && c1 > 1) wall_cells.push_back({r1-1, c1-1});
    if (r1 > 1 && c2 < GRID) wall_cells.push_back({r1-1, c2+1});
    if (r2 < GRID && c1 > 1) wall_cells.push_back({r2+1, c1-1});
    if (r2 < GRID && c2 < GRID) wall_cells.push_back({r2+1, c2+1});

    // Deduplicate
    std::sort(wall_cells.begin(), wall_cells.end());
    wall_cells.erase(std::unique(wall_cells.begin(), wall_cells.end()), wall_cells.end());

    // Interior target for humans
    int target_r = (r1 + r2) / 2;
    int target_c = (c1 + c2) / 2;

    for (int turn = 0; turn < TURNS; turn++) {
        std::string actions(M, '.');
        std::vector<std::pair<int,int>> builds_this_turn;

        for (int i = 0; i < M; i++) {
            int hr = humans[i].r, hc = humans[i].c;

            // Is human in interior?
            bool in_interior = (hr >= r1 && hr <= r2 && hc >= c1 && hc <= c2);

            if (!in_interior) {
                // Move toward interior center
                char mv = bfs_move(hr, hc, target_r, target_c);
                if (mv == '.') {
                    // Try moving toward any interior cell
                    int min_d = 999;
                    int best_tr = target_r, best_tc = target_c;
                    for (int r = r1; r <= r2; r++) {
                        for (int c = c1; c <= c2; c++) {
                            int d = std::abs(hr - r) + std::abs(hc - c);
                            if (d < min_d && !wall[r][c]) {
                                min_d = d;
                                best_tr = r; best_tc = c;
                            }
                        }
                    }
                    mv = bfs_move(hr, hc, best_tr, best_tc);
                }
                if (mv != '.') {
                    // Validate: won't move into wall or into a cell being built
                    for (int d = 0; d < 4; d++) {
                        if (mv == MOVE_CHAR[d]) {
                            int nr = hr + DR[d], nc = hc + DC[d];
                            if (!valid(nr, nc) || wall[nr][nc]) {
                                mv = '.';
                            } else {
                                bool blocked = false;
                                for (auto& b : builds_this_turn) {
                                    if (b.first == nr && b.second == nc) { blocked = true; break; }
                                }
                                if (blocked) mv = '.';
                            }
                            break;
                        }
                    }
                }
                actions[i] = mv;
                continue;
            }

            // Human is inside - try to build a wall cell
            // Find adjacent unbuilt wall cell
            int best_dir = -1;
            int best_wall_priority = 999999;
            for (int d = 0; d < 4; d++) {
                int wr = hr + DR[d], wc = hc + DC[d];
                if (!valid(wr, wc) || wall[wr][wc]) continue;

                // Is this a wall cell?
                bool is_wall_cell = false;
                int wall_idx = -1;
                for (int wi = 0; wi < (int)wall_cells.size(); wi++) {
                    if (wall_cells[wi].first == wr && wall_cells[wi].second == wc) {
                        is_wall_cell = true;
                        wall_idx = wi;
                        break;
                    }
                }
                if (!is_wall_cell) continue;

                // Check build constraints
                if (pet_on_or_adj(wr, wc)) continue;
                bool occupied = false;
                for (int j = 0; j < M; j++) {
                    if (humans[j].r == wr && humans[j].c == wc) { occupied = true; break; }
                }
                if (occupied) continue;
                for (auto& b : builds_this_turn) {
                    if (b.first == wr && b.second == wc) { occupied = true; break; }
                }
                if (occupied) continue;

                if (wall_idx < best_wall_priority) {
                    best_wall_priority = wall_idx;
                    best_dir = d;
                }
            }

            if (best_dir != -1) {
                actions[i] = BUILD_CHAR[best_dir];
                int wr = hr + DR[best_dir], wc = hc + DC[best_dir];
                builds_this_turn.push_back({wr, wc});
                continue;
            }

            // Not adjacent to any buildable wall - move toward one
            int min_dist = 999999;
            int move_target_r = -1, move_target_c = -1;
            for (auto& wc_pair : wall_cells) {
                int wr = wc_pair.first, wcc = wc_pair.second;
                if (wall[wr][wcc]) continue;

                // Find build position (interior cell adjacent to this wall cell)
                for (int d = 0; d < 4; d++) {
                    int br = wr + DR[d], bc = wcc + DC[d];
                    if (!valid(br, bc) || wall[br][bc]) continue;
                    if (br < r1 || br > r2 || bc < c1 || bc > c2) continue;
                    int dist = std::abs(hr - br) + std::abs(hc - bc);
                    if (dist < min_dist) {
                        min_dist = dist;
                        move_target_r = br;
                        move_target_c = bc;
                    }
                }
            }

            if (move_target_r != -1 && min_dist > 0) {
                char mv = bfs_move(hr, hc, move_target_r, move_target_c);
                if (mv != '.') {
                    for (int d = 0; d < 4; d++) {
                        if (mv == MOVE_CHAR[d]) {
                            int nr = hr + DR[d], nc = hc + DC[d];
                            if (!valid(nr, nc) || wall[nr][nc]) {
                                mv = '.';
                            } else {
                                bool blocked = false;
                                for (auto& b : builds_this_turn) {
                                    if (b.first == nr && b.second == nc) { blocked = true; break; }
                                }
                                if (blocked) mv = '.';
                            }
                            break;
                        }
                    }
                }
                actions[i] = mv;
            }
        }

        std::cout << actions << std::endl;

        // Update state
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            for (int d = 0; d < 4; d++) {
                if (a == BUILD_CHAR[d]) {
                    int wr = humans[i].r + DR[d], wc = humans[i].c + DC[d];
                    if (valid(wr, wc)) wall[wr][wc] = true;
                    break;
                }
            }
            for (int d = 0; d < 4; d++) {
                if (a == MOVE_CHAR[d]) {
                    int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                    if (valid(nr, nc) && !wall[nr][nc]) {
                        humans[i].r = nr;
                        humans[i].c = nc;
                    }
                    break;
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string mv;
            std::cin >> mv;
            if (mv == ".") continue;
            for (char ch : mv) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CHAR[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
